#[unsafe(no_mangle)]
pub extern "C" fn logos_module_set_context(
    module_path: *const c_char,
    instance_id: *const c_char,
    instance_persistence_path: *const c_char,
) {
    fn s(p: *const c_char) -> String {
        if p.is_null() {
            String::new()
        } else {
            unsafe { CStr::from_ptr(p) }.to_string_lossy().into_owned()
        }
    }
    *CONTEXT.lock().unwrap() = Some(RustModuleContext {
        module_path: s(module_path),
        instance_id: s(instance_id),
        instance_persistence_path: s(instance_persistence_path),
    });
    ensure_ready(true);
}

#[unsafe(no_mangle)]
pub extern "C" fn logos_module_set_emit_callback(cb: Option<EmitCb>, user_data: *mut c_void) {
    EMIT.lock().unwrap().cb = cb.map(|f| (f, user_data as usize));
    ensure_ready(true);
}

static TOKENS: Mutex<Vec<(String, String)>> = Mutex::new(Vec::new());

#[unsafe(no_mangle)]
pub extern "C" fn logos_module_accept_token(
    module_name: *const c_char,
    token: *const c_char,
) -> c_int {
    if module_name.is_null() || token.is_null() {
        return -1;
    }
    let name = unsafe { CStr::from_ptr(module_name) }
        .to_string_lossy()
        .into_owned();
    let tok = unsafe { CStr::from_ptr(token) }
        .to_string_lossy()
        .into_owned();
    logos_rust_sdk::save_token(&name, &tok);
    TOKENS.lock().unwrap().push((name, tok));
    0
}

